appsmith.onReady(loadList);
appsmith.onModelChange(loadList);
function loadList() {
  const el = document.getElementById('items');
  let operations = {};
  if (appsmith.model.newOrder) {
    operations = {
      label: appsmith.model.newOrder.label,
      values: appsmith.model.newOrder.values
    };
  } else {
    operations = {
      label: appsmith.model.Name,
      values: appsmith.model.values
    };
  }
  if (!operations || !operations.label || !operations.values) {
    return;
  }
  el.innerHTML = '';
  operations.label.forEach((label, opId) => {
    const listItem = document.createElement('li');
    listItem.textContent = label;
    listItem.dataset.value = operations.values[opId];
    el.appendChild(listItem);
  });
  Sortable.create(el, {
    onEnd: function () {
      const items = Array.from(el.children);
      const newOrder = items.map((item, index) => ({
        name: item.textContent.trim(),
        operationID: parseInt(item.dataset.value, 10),
        index: index + 1
      }));

      // Update the model with the new order
      appsmith.updateModel({
        newOrder: {
          label: newOrder.map(o => o.name),
          values: newOrder.map(o => o.operationID)
        }
      });
      appsmith.triggerEvent('Sequence Changed');
    }
  });
}

