() => {
  const data = Get_schedule_for_gantt.data;
  if (!data || !data.length) return "gantt\ntitle Production Schedule\n";
  const validData = data.filter(d => d.start_ts && d.end_ts);
  const groups = [...new Set(validData.map(d => d.machine))];
  let mermaidStr = "gantt\ntitle Production Schedule\ndateFormat YYYY-MM-DDTHH:mm\n";
  groups.forEach(group => {
    mermaidStr += `section ${group}\n`;
    validData.filter(d => d.machine === group).forEach(d => {
      const startRaw = d.start_ts.replace(" ", "T");
      const endRaw = d.end_ts.replace(" ", "T");
      const start = new Date(startRaw).toISOString().slice(0, 16);
      const end = new Date(endRaw).toISOString().slice(0, 16);
      const taskName = d.label || `Order ${d.order_id} - ${d.operation}`;
      mermaidStr += `${taskName} : ${start}, ${end}\n`;
    });
  });
  return mermaidStr;
}

