export default {
  generateGanttMermaid: () => {
    const data = Get_schedule_for_gantt.data;
    if (!data || !data.length) return "gantt\ntitle Production Schedule\n"; 

    // Filter out entries missing timestamps
    const validData = data.filter(d => d.start_ts && d.end_ts);

    const groups = [...new Set(validData.map(d => d.machine))];

    let mermaidStr = "gantt\ntitle Production Schedule\ndateFormat YYYY-MM-DDTHH:mm\n";

    groups.forEach(group => {
      mermaidStr += `section ${group}\n`;
      validData
        .filter(d => d.machine === group)
        .forEach(d => {
          const startRaw = d.start_ts.replace(" ", "T");
          const endRaw = d.end_ts.replace(" ", "T");
          const start = new Date(startRaw).toISOString().slice(0,16);
          const end = new Date(endRaw).toISOString().slice(0,16);
          const taskName = d.label || `Order ${d.order_id} - ${d.operation}`;
          mermaidStr += `${taskName} : ${start}, ${end}\n`;
        });
    });

    return mermaidStr;
  }
}

export default {
  fetchProductsFlattenedPretty: async () => {
    const products = await Get_product_operation2.run(); // fetch products with operations
    const operationsData = await Get_operations.run(); // fetch all operations with operation_id & name

    const flattened = [];

    for (const product of products) {
      let firstRow = true;
      for (const op of product.operations) {
        // Find the operation name from operations table
        const opName = operationsData.find(o => o.operation_id === op.operation_id)?.name || "";

        flattened.push({
          product_id: firstRow ? product.product_id : "",
          product_name: firstRow ? product.product_name : "",
          operation_id: op.operation_id,
          operation_name: opName,
          sequence: op.sequence
        });

        firstRow = false;
      }
    }

    return flattened; // ready to use in Table widget
  }
}

export default {
  make() {
    const productID = SelectProductID.selectedOptionValue;

    const production = OperationOrdering.model.newOrder || {
      label: OperationOrdering.model.Name,
      values: OperationOrdering.model.values
    };

    const result = production.label.map((label, i) => ({
      product_id: productID,
      operation_id: production.values[i],
      sequence: i + 1
    }));

    return result;
  }
}

