	productArray: [],
	collectInput(){
		const listId = this.productArray.length
		const newProduct = NewProductInput.text
		this.productArray.push({
			"id": listId,
			"name": newProduct
		})
	},

	clearArray(){
		this.productArray = []
	},

	deleteRow(){
		this.productArray.splice(AddProductTable.selectedRow.id, 1)
		AddProductTable.setSelectedRowIndex(-1)
	},

	getCleanArray(){
		const cleanArray = []
		for(const item of this.productArray) {
			cleanArray.push(item.name)
     }

		return cleanArray
	}
}
